You are building the Zustand store that bridges the pure game logic with the React UI and Phaser renderer.

The game core types and engine are at `/workspaces/cipherShot/src/game/core/`. Read the types from there first (they may still be in progress, so if they don't exist yet, use these types):

```typescript
type Player = 'player1' | 'player2';
type Target = 'self' | 'opponent';
type CardType = 'bluff' | 'redirect';
type ShotType = 'live' | 'blank';
type GamePhase = 'choosingTarget' | 'respondingCard' | 'resolving' | 'gameOver';
```

Create this file:

### `/workspaces/cipherShot/src/game/store.ts`

```typescript
import { create } from 'zustand';
import type { GameState, Target, CardType } from './core/types';
import { createInitialState, selectTarget, playCard } from './core/engine';

interface GameStore {
  // State
  gameState: GameState;
  animating: boolean; // true while Phaser is animating

  // Actions
  startGame: () => void;
  chooseTarget: (target: Target) => void;
  respondWithCard: (cardType: CardType | null) => void;
  setAnimating: (animating: boolean) => void;
  resetGame: () => void;
}

export const useGameStore = create<GameStore>((set, get) => ({
  gameState: createInitialState(),
  animating: false,

  startGame: () => {
    set({ gameState: createInitialState(), animating: false });
  },

  chooseTarget: (target: Target) => {
    const { gameState, animating } = get();
    if (animating || gameState.phase !== 'choosingTarget') return;
    set({ gameState: selectTarget(gameState, target) });
  },

  respondWithCard: (cardType: CardType | null) => {
    const { gameState, animating } = get();
    if (animating || gameState.phase !== 'respondingCard') return;
    const newState = playCard(gameState, cardType);
    set({ gameState: newState, animating: true });
    // Phaser will read animating=true, play animation, then call setAnimating(false)
  },

  setAnimating: (animating: boolean) => {
    set({ animating });
  },

  resetGame: () => {
    set({ gameState: createInitialState(), animating: false });
  },
}));
```

