  private createPlayers(): void {
    // Player 1 (left) - shadowy figure
    this.playerLeft = this.add.rectangle(200, GAME_HEIGHT/2 - 20, 80, 120, 0x2a2a3e);
    this.playerLeft.setStrokeStyle(1, 0x3a3a5e);
    this.playerLeftLabel = this.add.text(200, GAME_HEIGHT/2 - 90, 'P1', {
      fontFamily: 'monospace',
      fontSize: '14px',
      color: '#8888aa',
    }).setOrigin(0.5);

    // Player 2 (right) - shadowy figure
    this.playerRight = this.add.rectangle(760, GAME_HEIGHT/2 - 20, 80, 120, 0x2a2a3e);
    this.playerRight.setStrokeStyle(1, 0x3a3a5e);
    this.playerRightLabel = this.add.text(760, GAME_HEIGHT/2 - 90, 'P2', {
      fontFamily: 'monospace',
      fontSize: '14px',
      color: '#8888aa',
    }).setOrigin(0.5);
  }

  private createGun(): void {
    // Gun on table center
    this.gun = this.add.rectangle(GAME_WIDTH/2, GAME_HEIGHT/2 + 30, 60, 24, 0x555566);
    this.gun.setStrokeStyle(1, 0x777788);
    this.gunLabel = this.add.text(GAME_WIDTH/2, GAME_HEIGHT/2 + 30, 'GUN', {
      fontFamily: 'monospace',
      fontSize: '10px',
      color: '#aaaacc',
    }).setOrigin(0.5);
  }

  private createLampEffect(): void {
    // Hanging lamp cone of light
    this.lampLight = this.add.ellipse(GAME_WIDTH/2, GAME_HEIGHT/2 + 20, 400, 300, 0xffdd88, 0.04);

    // Lamp fixture
    this.add.rectangle(GAME_WIDTH/2, 10, 4, 20, 0x666666);
    this.add.rectangle(GAME_WIDTH/2, 24, 30, 10, 0x887744);

    // Small bright spot under lamp
    this.add.ellipse(GAME_WIDTH/2, GAME_HEIGHT/2 + 40, 120, 60, 0xffeeaa, 0.06);
  }

  private createMuzzleFlash(): void {
    this.muzzleFlash = this.add.ellipse(GAME_WIDTH/2, GAME_HEIGHT/2 + 30, 40, 40, 0xffff00, 0);
  }

  // --- PUBLIC ANIMATION METHODS (called from React/store) ---

  public highlightShooter(player: 'player1' | 'player2'): void {
    const target = player === 'player1' ? this.playerLeft : this.playerRight;
    const other = player === 'player1' ? this.playerRight : this.playerLeft;

    target.setStrokeStyle(2, 0xff4444);
    other.setStrokeStyle(1, 0x3a3a5e);
  }

  public animateAim(shooter: 'player1' | 'player2', target: 'self' | 'opponent'): void {
    const isLeft = shooter === 'player1';
    const aimX = target === 'self' 
      ? (isLeft ? 240 : 720) 
      : (isLeft ? 720 : 240);

    this.tweens.add({
      targets: this.gun,
      x: aimX,
      duration: 400,
      ease: 'Power2',
    });
    this.tweens.add({
      targets: this.gunLabel,
      x: aimX,
      duration: 400,
      ease: 'Power2',
    });
  }

  public animateShot(isLive: boolean, onComplete: () => void): void {
    if (isLive) {
      // Flash
      this.muzzleFlash.setPosition(this.gun.x, this.gun.y);
      this.muzzleFlash.setAlpha(1);

      // Camera shake
      this.cameras.main.shake(300, 0.01);

      // Gun recoil
      this.tweens.add({
        targets: [this.gun, this.gunLabel],
        x: this.gun.x + (this.gun.x < GAME_WIDTH/2 ? -15 : 15),
        duration: 50,
        yoyo: true,
        ease: 'Power4',
      });

      // Flash fade
      this.tweens.add({
        targets: this.muzzleFlash,
        alpha: 0,
        scaleX: 3,
        scaleY: 3,
        duration: 300,
        onComplete: () => {
          this.muzzleFlash.setScale(1);
          onComplete();
        },
      });
    } else {
      // Click sound visual - small shake only
      this.cameras.main.shake(100, 0.003);
      this.time.delayedCall(400, onComplete);
    }
  }

  public resetGunPosition(): void {
    this.tweens.add({
      targets: [this.gun, this.gunLabel],
      x: GAME_WIDTH / 2,
      duration: 300,
      ease: 'Power2',
    });
  }

  public showKill(player: 'player1' | 'player2'): void {
    const target = player === 'player1' ? this.playerLeft : this.playerRight;

    this.tweens.add({
      targets: target,
      alpha: 0.3,
      y: target.y + 30,
      duration: 500,
      ease: 'Power2',
    });

    // Red flash on screen
    const flash = this.add.rectangle(GAME_WIDTH/2, GAME_HEIGHT/2, GAME_WIDTH, GAME_HEIGHT, 0xff0000, 0.3);
    this.tweens.add({
      targets: flash,
      alpha: 0,
      duration: 800,
      onComplete: () => flash.destroy(),
    });
  }

  // Display chamber status (dots at top)
  public updateChamberDisplay(total: number, currentIndex: number): void {
    this.chamberDots.forEach(d => d.destroy());
    this.chamberDots = [];

    const startX = GAME_WIDTH/2 - (total * 16) / 2;
    for (let i = 0; i < total; i++) {
      const color = i < currentIndex ? 0x444455 : (i === currentIndex ? 0xffffff : 0x666677);
      const dot = this.add.circle(startX + i * 16, 20, 4, color);
      this.chamberDots.push(dot);
    }
  }
}
```

