 4→
 5→interface GameStore {
 6→  // State
 7→  gameState: GameState;
 8→  animating: boolean; // true while Phaser is animating
 9→
10→  // Actions
11→  startGame: () => void;
12→  chooseTarget: (target: Target) => void;
13→  respondWithCard: (cardType: CardType | null) => void;
14→  setAnimating: (animating: boolean) => void;
15→  resetGame: () => void;
16→}
