18→export const useGameStore = create<GameStore>((set, get) => ({
19→  gameState: createInitialState(),
20→  animating: false,
21→
22→  startGame: () => {
23→    set({ gameState: createInitialState(), animating: false });
24→  },
25→
26→  chooseTarget: (target: Target) => {
27→    const { gameState, animating } = get();
28→    if (animating || gameState.phase !== 'choosingTarget') return;
29→    set({ gameState: selectTarget(gameState, target) });
30→  },
31→
32→  respondWithCard: (cardType: CardType | null) => {
33→    const { gameState, animating } = get();
34→    if (animating || gameState.phase !== 'respondingCard') return;
35→    const newState = playCard(gameState, cardType);
36→    set({ gameState: newState, animating: true });
37→    // Phaser will read animating=true, play animation, then call setAnimating(false)
38→  },
39→
40→  setAnimating: (animating: boolean) => {
41→    set({ animating });
42→  },
43→
44→  resetGame: () => {
45→    set({ gameState: createInitialState(), animating: false });
46→  },
47→}));
