189→
190→    // Red flash on screen
191→    const flash = this.add.rectangle(GAME_WIDTH / 2, GAME_HEIGHT / 2, GAME_WIDTH, GAME_HEIGHT, 0xff0000, 0.3);
192→    this.tweens.add({
193→      targets: flash,
