195→      duration: 800,
196→      onComplete: () => flash.destroy(),
197→    });
198→  }
199→
200→  // Display chamber status (dots at top)
201→  public updateChamberDisplay(total: number, currentIndex: number): void {
202→    this.chamberDots.forEach(d => d.destroy());
203→    this.chamberDots = [];
204→
205→    const startX = GAME_WIDTH / 2 - (total * 16) / 2;
206→    for (let i = 0; i < total; i++) {
207→      const color = i < currentIndex ? 0x444455 : (i === currentIndex ? 0xffffff : 0x666677);
208→      const dot = this.add.circle(startX + i * 16, 20, 4, color);
