  1→import type { CardType, GameState, Player, Target } from './types';
  2→import { generateChamber } from './chamber';
  3→import { generatePlayerCards, canPlayCard, markCardUsed } from './cards';
  4→import { resolveShot } from './resolver';
  5→
  6→/**
  7→ * Return the opponent of the given player.
  8→ */
  9→export function getResponder(shooter: Player): Player {
 10→  return shooter === 'player1' ? 'player2' : 'player1';
 11→}
 12→
 13→/**
 14→ * Create the initial game state for a new game.
 15→ */
 16→export function createInitialState(): GameState {
 17→  return {
 18→    phase: 'choosingTarget',
 19→    currentShooter: 'player1',
 20→    chamber: generateChamber(),
 21→    currentShotIndex: 0,
 22→    players: {
 23→      player1: { cards: generatePlayerCards(), alive: true },
 24→      player2: { cards: generatePlayerCards(), alive: true },
 25→    },
 26→    selectedTarget: null,
 27→    respondedCard: null,
 28→    lastResult: null,
 29→    winner: null,
 30→    shotHistory: [],
 31→  };
 32→}
 33→
 34→/**
 35→ * The current shooter selects a target ('self' or 'opponent').
 36→ * Transitions to the 'respondingCard' phase.
 37→ */
 38→export function selectTarget(state: GameState, target: Target): GameState {
 39→  if (state.phase !== 'choosingTarget') {
 40→    return state;
 41→  }
 42→
 43→  return {
 44→    ...state,
 45→    selectedTarget: target,
 46→    phase: 'respondingCard',
 47→  };
 48→}
 49→
 50→/**
 51→ * The responder plays a card (or null to skip).
 52→ * Then the shot is resolved immediately.
 53→ */
 54→export function playCard(
 55→  state: GameState,
 56→  cardType: CardType | null,
 57→): GameState {
 58→  if (state.phase !== 'respondingCard') {
 59→    return state;
 60→  }
 61→
 62→  const responder = getResponder(state.currentShooter);
 63→
 64→  // Validate card play
 65→  if (cardType !== null && !canPlayCard(state.players[responder].cards, cardType)) {
 66→    return state;
 67→  }
 68→
 69→  // Mark the card as used if one was played
 70→  let updatedPlayers = { ...state.players };
 71→  if (cardType !== null) {
 72→    const responderCards = state.players[responder].cards;
 73→    const cardToUse = responderCards.find((c) => c.type === cardType && !c.used);
 74→    if (cardToUse) {
 75→      updatedPlayers = {
 76→        ...updatedPlayers,
 77→        [responder]: {
 78→          ...updatedPlayers[responder],
 79→          cards: markCardUsed(responderCards, cardToUse.id),
 80→        },
 81→      };
 82→    }
 83→  }
 84→
 85→  // Build intermediate state for resolution
 86→  const stateForResolve: GameState = {
 87→    ...state,
 88→    respondedCard: cardType,
 89→    players: updatedPlayers,
 90→  };
 91→
 92→  return resolveAndAdvance(stateForResolve);
 93→}
 94→
 95→/**
 96→ * Internal: resolve the shot outcome, check for kill, and advance the game.
 97→ * Returns a new GameState — never mutates.
 98→ */
 99→function resolveAndAdvance(state: GameState): GameState {
100→  const result = resolveShot(state);
101→  const newHistory = [...state.shotHistory, result];
102→
103→  // Apply kill if the shot was live
104→  let updatedPlayers = { ...state.players };
105→  if (result.killed) {
106→    updatedPlayers = {
107→      ...updatedPlayers,
108→      [result.finalTarget]: {
109→        ...updatedPlayers[result.finalTarget],
110→        alive: false,
111→      },
112→    };
113→  }
114→
115→  // Check for game over
116→  if (result.killed) {
117→    const winner = getResponder(result.finalTarget as Player);
118→    return {
119→      ...state,
120→      phase: 'gameOver',
121→      players: updatedPlayers,
122→      lastResult: result,
123→      winner,
124→      shotHistory: newHistory,
125→      selectedTarget: null,
126→      respondedCard: null,
127→    };
128→  }
129→
130→  // No kill — advance to next shot
131→  const nextShotIndex = state.currentShotIndex + 1;
132→
133→  // If we've exhausted the chamber, game ends in a draw-like state
134→  // (shouldn't happen with 3 live rounds, but handle gracefully)
135→  if (nextShotIndex >= state.chamber.length) {
136→    return {
137→      ...state,
138→      phase: 'gameOver',
139→      players: updatedPlayers,
140→      lastResult: result,
141→      winner: null,
142→      shotHistory: newHistory,
143→      currentShotIndex: nextShotIndex,
144→      selectedTarget: null,
145→      respondedCard: null,
146→    };
147→  }
148→
149→  // Swap shooter and responder for the next turn
150→  const nextShooter = getResponder(state.currentShooter);
151→
152→  return {
153→    ...state,
154→    phase: 'choosingTarget',
155→    currentShooter: nextShooter,
156→    currentShotIndex: nextShotIndex,
157→    players: updatedPlayers,
158→    lastResult: result,
159→    selectedTarget: null,
160→    respondedCard: null,
161→    winner: null,
162→    shotHistory: newHistory,
163→  };
164→}
