 1→export type Player = 'player1' | 'player2';
 2→export type Target = 'self' | 'opponent';
 3→export type CardType = 'bluff' | 'redirect';
 4→export type ShotType = 'live' | 'blank';
 5→export type GamePhase = 'choosingTarget' | 'respondingCard' | 'resolving' | 'gameOver';
 6→
 7→export interface Card {
 8→  id: string;
 9→  type: CardType;
10→  used: boolean;
11→}
12→
13→export interface PlayerState {
14→  cards: Card[];
15→  alive: boolean;
16→}
17→
18→export interface ShotResult {
19→  shotType: ShotType;
20→  shooter: Player;
21→  originalTarget: Target;
22→  cardPlayed: CardType | null;
23→  finalTarget: Player;
24→  killed: boolean;
25→}
26→
27→export interface GameState {
28→  phase: GamePhase;
29→  currentShooter: Player;
30→  chamber: ShotType[];
31→  currentShotIndex: number;
32→  players: Record<Player, PlayerState>;
33→  selectedTarget: Target | null;
34→  respondedCard: CardType | null;
35→  lastResult: ShotResult | null;
36→  winner: Player | null;
37→  shotHistory: ShotResult[];
38→}
