 1→import type { CardType, GameState, Player, ShotResult, Target } from './types';
 2→
 3→/**
 4→ * Return the opponent of a given player.
 5→ */
 6→function opponentOf(player: Player): Player {
 7→  return player === 'player1' ? 'player2' : 'player1';
 8→}
 9→
10→/**
11→ * Resolve who actually gets shot after considering the card played.
12→ *
13→ * - bluff (or null): no effect — target stays as chosen.
14→ * - redirect: flips the target.
15→ *   - 'self' becomes opponent, 'opponent' becomes self.
16→ */
17→export function resolveTarget(
18→  shooter: Player,
19→  originalTarget: Target,
20→  cardPlayed: CardType | null,
21→): Player {
22→  const redirected = cardPlayed === 'redirect';
23→
24→  if (originalTarget === 'self') {
25→    return redirected ? opponentOf(shooter) : shooter;
26→  }
27→  // originalTarget === 'opponent'
28→  return redirected ? shooter : opponentOf(shooter);
29→}
30→
31→/**
32→ * Resolve the current shot using the game state.
33→ * Returns a complete ShotResult without mutating state.
34→ */
35→export function resolveShot(state: GameState): ShotResult {
36→  const shotType = state.chamber[state.currentShotIndex];
37→  const shooter = state.currentShooter;
38→  const originalTarget = state.selectedTarget!;
39→  const cardPlayed = state.respondedCard;
40→
41→  const finalTarget = resolveTarget(shooter, originalTarget, cardPlayed);
42→  const killed = shotType === 'live';
43→
44→  return {
45→    shotType,
46→    shooter,
47→    originalTarget,
48→    cardPlayed,
49→    finalTarget,
50→    killed,
51→  };
52→}
