 1→import type { Card, CardType } from './types';
 2→
 3→let cardCounter = 0;
 4→
 5→function nextCardId(): string {
 6→  cardCounter += 1;
 7→  return `card-${cardCounter}`;
 8→}
 9→
10→/**
11→ * Generate 5 cards for a player: 3 bluff, 2 redirect.
12→ * Each card has a unique ID.
13→ */
14→export function generatePlayerCards(): Card[] {
15→  const types: CardType[] = ['bluff', 'bluff', 'bluff', 'redirect', 'redirect'];
16→  return types.map((type) => ({
17→    id: nextCardId(),
18→    type,
19→    used: false,
20→  }));
21→}
22→
23→/**
24→ * Check whether the player has an unused card of the given type.
25→ */
26→export function canPlayCard(cards: readonly Card[], type: CardType): boolean {
27→  return cards.some((c) => c.type === type && !c.used);
28→}
29→
30→/**
31→ * Return a new cards array with the specified card marked as used.
32→ */
33→export function markCardUsed(cards: readonly Card[], cardId: string): Card[] {
34→  return cards.map((c) =>
35→    c.id === cardId ? { ...c, used: true } : { ...c },
36→  );
37→}
38→

 1→import type { ShotType } from './types';
 2→
 3→/**
 4→ * Fisher-Yates shuffle (pure — returns a new array).
 5→ */
 6→function shuffle<T>(source: readonly T[]): T[] {
 7→  const arr = [...source];
 8→  for (let i = arr.length - 1; i > 0; i--) {
 9→    const j = Math.floor(Math.random() * (i + 1));
10→    const tmp = arr[i];
11→    arr[i] = arr[j];
12→    arr[j] = tmp;
13→  }
14→  return arr;
15→}
16→
17→/**
18→ * Generate a shuffled chamber with 3 live rounds and 4 blanks (7 total).
19→ */
20→export function generateChamber(): ShotType[] {
21→  const rounds: ShotType[] = [
22→    'live', 'live', 'live',
23→    'blank', 'blank', 'blank', 'blank',
24→  ];
25→  return shuffle(rounds);
26→}
