19→      {history.map((shot, i) => {
20→        const shooter = shot.shooter === 'player1' ? 'P1' : 'P2';
21→        const target = shot.finalTarget === 'player1' ? 'P1' : 'P2';
22→        const card = shot.cardPlayed ? ` [${shot.cardPlayed.toUpperCase()}]` : '';
23→        const result = shot.killed ? '💀' : (shot.shotType === 'live' ? '🔴' : '⚪');
24→        return (
25→          <div key={i}>
26→            #{i + 1}: {shooter}→{target}{card} {result} {shot.shotType.toUpperCase()}
27→          </div>
28→        );
29→      })}
30→    </div>
31→  );
